mapper.select:
SELECT COUNT(1)
FROM log_operation o
WHERE 1 = 1

      AND o.username LIKE CONCAT('%', #{query.username}, '%')


      AND o.operation_module = #{query.operationModule}


      AND o.operation_type = #{query.operationType}


      AND o.success_flag = #{query.successFlag}


      AND o.trace_id = #{query.traceId}


      AND o.operation_time  >=  #{query.startTime}


      AND o.operation_time  <=  #{query.endTime}

SELECT id, user_id, username, operation_module, operation_type, request_uri, request_method, request_body,
       response_body, success_flag, error_message, trace_id, operation_time
FROM log_operation o
WHERE 1 = 1

      AND o.username LIKE CONCAT('%', #{query.username}, '%')


      AND o.operation_module = #{query.operationModule}


      AND o.operation_type = #{query.operationType}


      AND o.success_flag = #{query.successFlag}


      AND o.trace_id = #{query.traceId}


      AND o.operation_time  >=  #{query.startTime}


      AND o.operation_time  <=  #{query.endTime}

ORDER BY o.operation_time DESC, o.id DESC
LIMIT #{size} OFFSET #{offset}
